class KthLargest {
    int[] nums;
    int k;

    public KthLargest(int k, int[] nums) {
        this.k = k;
        this.nums = nums.clone();
    }

    public int add(int val) {
        Arrays.sort(nums);
        nums[k] = val;
        return nums[k - 1];
    }
}
